   private Set<String> initializedVars = new HashSet<String>();
   private Set<String> localVars       = new HashSet<String>();

   private boolean inMethodScope  = false;
   private boolean inLHSContext   = false;

   private boolean finalAssigned      = false;
   private boolean uninitializedUsed  = false;

