/**
 * f0 -> "while"
 * f1 -> "("
 * f2 -> Expression()
 * f3 -> ")"
 * f4 -> Statement()
 *
 * The loop body may execute zero times, so any variable first assigned
 * inside the body is NOT definitely initialized after the loop.
 * We snapshot initializedVars before the body and restore it after,
 * but still visit the body so we catch reads of uninitialized vars inside.
 */
public R visit(WhileStatement n, A argu) {
   R _ret=null;
   // Visit condition (reads here use the pre-loop initialized set)
   n.f2.accept(this, argu);

   // Snapshot before body -- the body may not execute at all
   Set<String> beforeBody = new HashSet<String>(initializedVars);

   // Visit body (detects uninitialized reads inside the loop)
   n.f4.accept(this, argu);

   // Restore: assignments inside the body don't count as definite
   initializedVars = beforeBody;

   return _ret;
}

/**
 * f0 -> "if"
 * f1 -> "("
 * f2 -> Expression()
 * f3 -> ")"
 * f4 -> Statement()   <-- then-branch
 * f5 -> "else"
 * f6 -> Statement()   <-- else-branch
 *
 * A variable is definitely initialized after an if-else only if it is
 * initialized in BOTH branches. We compute each branch's initialized set
 * independently and take their intersection (merged with what was already
 * initialized before).
 */
public R visit(IfStatement n, A argu) {
   R _ret=null;
   // Visit condition
   n.f2.accept(this, argu);

   // Snapshot the state entering both branches
   Set<String> beforeBranches = new HashSet<String>(initializedVars);

   // Visit then-branch
   n.f4.accept(this, argu);
   Set<String> afterThen = new HashSet<String>(initializedVars);

   // Reset to pre-branch state, visit else-branch
   initializedVars = new HashSet<String>(beforeBranches);
   n.f6.accept(this, argu);
   Set<String> afterElse = new HashSet<String>(initializedVars);

   // After if-else: only vars initialized in BOTH branches are definite
   afterThen.retainAll(afterElse);   // intersection
   initializedVars = afterThen;

   return _ret;
}

