    * f7 -> ";"
    * f8 -> Identifier()    <-- update LHS (write -- may not execute)
    * f9 -> "="
    * f10 -> Expression()   <-- update RHS (read -- may not execute)
    * f11 -> ")"
    * f12 -> Statement()    <-- body (may not execute)
    *
    * The init part (f2=f4) definitely executes. The condition (f6) definitely
    * executes. The body (f12) and update (f8=f10) may not execute if the
    * condition is false from the start. So we snapshot before the body+update
    * and restore initializedVars after.
    */
   public R visit(ForStatement n, A argu) {
      R _ret=null;

      String initVar   = n.f2.f0.tokenImage;
      String updateVar = n.f8.f0.tokenImage;

      // Init assignment -- always executes
      if (finalVars.contains(initVar)) {
         finalAssigned = true;
         return _ret;
      }
      n.f4.accept(this, argu);  // init RHS
      if (localVars.contains(initVar)) {
         initializedVars.add(initVar);
      }

      // Condition -- always executes (at least once)
      n.f6.accept(this, argu);

      // Snapshot before body+update -- they may not execute
      Set<String> beforeLoop = new HashSet<String>(initializedVars);

      // Check update assignment (may assign a final)
      if (finalVars.contains(updateVar)) {
         finalAssigned = true;
         return _ret;
      }
      // Visit body
      n.f12.accept(this, argu);

      // Visit update RHS and mark update var (still inside "may not run" zone)
      n.f10.accept(this, argu);
      if (localVars.contains(updateVar)) {
         initializedVars.add(updateVar);
      }

      // Restore: body+update assignments are not definite
      initializedVars = beforeLoop;

      return _ret;
   }

